Here's a modern MSTest approach using `MockHttpMessageHandler`, async test methods, and proper timeout/cancellation patterns:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it hangs beyond 5s
    public async Task FetchAsync_HonorsCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler
    private sealed class MockHttpMessageHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` test methods | MSTest natively awaits them — no `GetAwaiter().GetResult()` needed |
| `[Timeout(ms)]` | Guards against hangs; works with async methods in MSTest v3+ |
| `Assert.ThrowsExactlyAsync` | MSTest v3+ preferred over `ThrowsExceptionAsync` (exact type match, no subclass) |
| `CancellationToken` forwarding | Verified by pre-cancelling and asserting `TaskCanceledException` |
| Custom `HttpMessageHandler` | Avoids mocking frameworks; gives full control over HTTP responses |

> **Note:** `Assert.ThrowsExactlyAsync` requires **MSTest 3.4+**. If on an older version, use `Assert.ThrowsExceptionAsync<T>` instead.
